using TranSmart.Core.Result;
using TranSmart.Data;
using TranSmart.Data.Paging;
using TranSmart.Domain.Entities.Organization;
using TranSmart.Domain.Models;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System;
using System.Linq;
using System.Threading.Tasks;

namespace TranSmart.Service.Organization
{
    public partial interface ILocationService : IBaseService<Location>
    {

    }

    public partial class LocationService : BaseService<Location>, ILocationService
    {
        public LocationService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(Location item, Result<Location> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Location>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Location.Name), "Name already exists"));
            }
        }
        public override async Task<Location> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Location>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.State).Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<Location>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<Location>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<Location>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Location>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)
                     || x.State.Name.Contains(search.Name)
                     || x.Shift.Name.Contains(search.Name)),
                include: i => i.Include(x => x.State).Include(x => x.Shift).Include(x => x.WeekOffSetup).Include(x => x.WorkHoursSetting),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
    }
